  "sql": "SELECT S.BLUEPRINTID AS blueprint_id, S.NAME, S.CLASS, S.ISPROFILEENABLED, S.UPDATEDTIME AS updated_time, S.REQUIREDFIELDS AS required_fields, COUNT(DISTINCT SD.COLLECTIONID) AS collection_count, COUNT(DISTINCT SA.PROPERTY) AS property_count FROM DIM_BLUEPRINT AS S LEFT JOIN HKG_BR_BLUEPRINT_COLLECTION AS SD ON S.BLUEPRINTID = SD.BLUEPRINTID LEFT JOIN HKG_BR_BLUEPRINT_PROPERTY AS SA ON S.BLUEPRINTID = SA.BLUEPRINTID WHERE LOWER(S.NAME) = LOWER('weRetail: CRM') GROUP BY S.BLUEPRINTID, S.NAME, S.CLASS, S.ISPROFILEENABLED, S.UPDATEDTIME, S.REQUIREDFIELDS LIMIT 3"
